module multi_8bit(
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);

    reg [15:0] partial_product;
    reg [7:0] multiplier;
    reg [15:0] shifted_A;
    integer i;

    always @(*) begin
        partial_product = 0;
        shifted_A = A;
        multiplier = B;
        for (i = 0; i < 8; i = i + 1) begin
            if (multiplier[i]) begin
                partial_product = partial_product + shifted_A;
            end
            shifted_A = {shifted_A[14:0], 1'b0};
        end
    end

    always @(*) begin
        product = partial_product;
    end

endmodule
